INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027dd8e3c98b0941765b89', 'Tony Betty  帮忙办理入住的，服务特别周到，酒店环境很哇塞啊，真不愧是超五星酒店。', '["https://dimg04.c-ctrip.com/images/0234y12000eunj7dbD307_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000euni6umF493_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000eungl02543A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000eunn8zz47AD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '花园大床房', '大床房', '家庭亲子', 46, 0, 1, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027dd8e3c98b0941765b8a', '老牌酒店，火车站附近，有特色，花园漂亮，好看，自助餐也ok，住宿和服务都很不错。之前在这里参加过宴会，印象深刻，所以选择了这里。有机会再订。', '["https://dimg04.c-ctrip.com/images/0231z12000ckxc5vkBF00_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000ckxc5vmC716_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000ckxdyyp512E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-11-16', '花园大床房', '大床房', '商务出差', 70, 0, 31, 6, '["周边配套","整体满意度","餐饮设施"]'::jsonb, '周边配套', '整体满意度', '餐饮设施'),
('68027dd8e3c98b0941765b8b', '国庆期间住了两晚，优点：1.酒店外观大气，花园瀑布很特别，不愧为90年代白金五星级酒店。2.不管是大厅还是楼道电梯口，都有服务员主动招呼，礼貌周到。3.酒店三楼的博物馆很棒，了解酒店业历史，有收获。4.淋浴喷头出水大洗浴畅快。
缺点：1.酒店挨着建设路一头在施工，白天机器轰鸣声很响影响休息。2.客房设施陈旧，说2019年有装修，不管是柜子，洗脸池，还是卫生间，都显得很老旧。3.床垫偏软，楼层高度偏低有压抑感。4.房间下水道有异味，半夜被熏醒。5.大厅有点暗，可能是国庆，也可能是里面餐厅较多，来来往往人多有闹市感。
总体评价，外观和软件五星酒店，房间和设施经济型，性价比不高。', '["https://dimg04.c-ctrip.com/images/0231w12000ccghxos50F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000ccgeivb5FBE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000ccgfexx2CF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 290, 6, 4, 9, '["房间设施","安静程度","性价比"]'::jsonb, '房间设施', '安静程度', '性价比'),
('68027dd8e3c98b0941765b8c', '服务态度很好，提前电话确认出行人数和是否有特殊要求，安排好孩子的洗漱用品和拖鞋，入住期间卫生做的也很到位。距离各旅游景点都不远，地铁站也很近，对面的广州酒家早茶很不错，酒店唯一需要改进的是28层的早餐，味道太一般了。生日的这天酒店准备了生日蛋糕非常贴心和感动，推荐亲子休闲游的入住。', '["https://dimg04.c-ctrip.com/images/0233u12000cbxxmfj982A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000cbxwjqm3FCD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000cbxzvv62034_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000cbxw8g5BF6F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '红棉大床套房', '套房', '家庭亲子', 141, 0, 10, 9, '["前台服务","交通便利性","周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套'),
('68027dd8e3c98b0941765b8d', '花园酒店不愧为广州市地标建筑，虽然节日期间客人暴多，但是整个大堂井然有序。接待员在了解我们想要加床就给我们升级到套间房，等我们入住时外加的床都已经铺好，且洗漱用品都变成了3位，可见酒店服务的细心周到。早餐人多，但是排队等位也很快，都有服务员引导，不会让人感觉乱糟糟的，也不会有人抢位置。', '["https://dimg04.c-ctrip.com/images/0232j12000cbjawpv91D1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000cbje105EB43_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cbjeto5AA25_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000cbjfcbz56D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000cbjhb3248E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000cbjd9iv5DC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000cbjevkx5191_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '花园双床房', '双床房', '朋友出游', 143, 1, 16, 9, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('68027de5e3c98b0941765b8e', '一天换三房，房间对铁轨施工，无语', '["https://dimg04.c-ctrip.com/images/0233212000dciyjgn0BFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-03-05', '花园双床房', '双床房', '商务出差', 16, 0, 2, 5, '["安静程度","客房服务"]'::jsonb, '安静程度', '客房服务', NULL),
('68027de5e3c98b0941765b8f', '一直拖着，现在才来点评。国庆节出行广州是临时起意，广州虽然去过多次，但是依然很喜欢。花园酒店是老五星酒店，有历史，有底蕴，是我喜欢的类型，又在市中心，做什么都方便。到店不仅送了生日蛋糕，还送了与博物馆联名的月饼，处处可见文化的味道。唯一有点遗憾的是国庆节的气温居然有35、36度，当然在酒店还是很舒服的，只想给个赞', '["https://dimg04.c-ctrip.com/images/0201r12000csbgtnn145E_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235h12000csb8nt46839_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000csb42xy1386_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000csb7msf4D71_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000csbfsb5813C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000csbf0hy8E6A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000csbc5ugFF83_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-23', '花园双床房', '双床房', '家庭亲子', 157, 0, 4, 8, '["整体满意度","周边配套","前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务'),
('68027de5e3c98b0941765b90', '除了大堂像五星酒店，房间是超级小，连个四星的都不如，而且淋雨和浴缸在一起，要站在浴缸里才能淋浴。私密性超级差，关上洗澡间的门，厕所就没门了。床挨着洗手台，连个隔断都没有。还有我已经支付了房费，还收了我500元押金，今天都回来了，还没给我退款。这是啥操作？', '["https://dimg04.c-ctrip.com/images/0235g12000cb7n7za27D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000cb7ejts40CC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 127, 0, 3, 9, '["房间设施","退房/入住效率"]'::jsonb, '房间设施', '退房/入住效率', NULL),
('68027de5e3c98b0941765b91', '房间还是可以的，主要是安全问题很好 每一层有一个服务员 可以观察到每个房间 就是前台办理很慢 程序很复杂比较浪费时间，洗发水不建议用了 太次了 ，床很舒服，有好有坏吧！整体还是可以的', '["https://dimg04.c-ctrip.com/images/0236r12000ce45coe7A4D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000ce4ad40BCAE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-15', '城央绿意大床房', '大床房', '商务出差', 91, 0, 24, 6, '["前台服务","退房/入住效率","房间设施"]'::jsonb, '前台服务', '退房/入住效率', '房间设施'),
('68027de5e3c98b0941765b92', '氛围感很好 入口有乐队 小姐姐发小礼物（糖果??）可以带娃来体验一下。
瀑布餐厅很赞。早上需要排队（5-10分钟）
建议酒店提供儿童洗漱用品和小拖鞋。
btw 大学课本上就有的建筑 10多年后终于见到了哈哈哈。', '["https://dimg04.c-ctrip.com/images/0231o12000cbe6kew050A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '红棉大床套房', '套房', '家庭亲子', 105, 0, 3, 7, '["整体满意度","餐饮设施","客房服务"]'::jsonb, '整体满意度', '餐饮设施', '客房服务'),
('68027de5e3c98b0941765b93', '吹爆这家酒店的服务！
一到酒店门口，礼宾就冲过来帮我拿行李箱，还和我说登记后叫我找他们拿行李去房间；前台check in给升级了套房；到了楼层上，老妈拖着箱子拖不动，客房服务经理看到马上过来帮我们推到房间。到房间后，打电话问客房服务有没有宝宝拖鞋，五分钟后马上有阿姨送来宝宝拖鞋宝宝牙刷宝宝洗发水沐浴露。真的太棒了。
酒店虽然是老酒店，但是维护的很好，环境各方面都很好。
周边集吃住行一体，楼下就是地铁站，对面是什么商场。下次来还住这！', '["https://dimg04.c-ctrip.com/images/0234z12000dd39ygy784A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000dd3ad7f47B0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-07', '花园大床房', '大床房', '家庭亲子', 218, 0, 7, 9, '["前台服务","客房服务","交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性'),
('68027de5e3c98b0941765b94', '谢谢携程这次套餐活动很给力！
酒店住了2晚，有褒有贬，但瑕不掩瑜！
第一天check-in,前台 Gillian 很热情地送了3支康乃馨，感觉很温馨！很巧，check out 也是她！我要特别感谢3位不知名的工作人员，一位是前台帅帅的老外好像是明先生，29号当我外面回来时发现房卡开不了门了，刚到大厅他就问我有什么需要帮忙的吗，经核实确认我订了2晚的房间后主动给我延房以表歉意！另一位是30号下午5点的金牌讲解员，虽然只有我一个人听讲，他依然非常专业认真，非常nice!让我进一步了解了酒店！也能感受到他对酒店的热爱！另一位要感谢的是30号下午我在听讲解时主动帮我去拿袋子装外套的一位穿金色连衣裙的前台小姐姐！当然还有餐厅、客房的服务都非常好??
扣分的是：我到机场收到邮件发现发票只开了一晚，打电话过去说马上补开，至今未收到！', '["https://dimg04.c-ctrip.com/images/0231a12000d3xhvipDEC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000d3xorp141CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000d3xzhi534E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000d3xqzap3E3D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000d3y0edgDEAC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-02', '红棉大床套房', '套房', '商务出差', 364, 0, 21, 8, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027de5e3c98b0941765b95', '女儿特别满意，尤其是露天游泳池，有特饮赠送，水质水温都很好。玩得不肯走。
房间设施标准很高，有咖啡机。装修时间长了，家具和地板有年代感，但卫生很好。没有浴缸是个瑕疵。洗浴用品是进口的，品质不错。总在外面玩，没看电视。不评论。
瀑布餐厅环境不错，早餐食物出品不错。口味中规中矩。
就是办理入住，拿到房卡时间超出预期，节日期间可以理解。期间有表演，小朋友还收到了礼物。', '["https://dimg04.c-ctrip.com/images/0230t12000cb5cl1n0975_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000cb5jg0v3446_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000cb5gyme5C9B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 182, 0, 10, 8, '["公共设施","房间设施","退房/入住效率"]'::jsonb, '公共设施', '房间设施', '退房/入住效率'),
('68027de5e3c98b0941765b96', '订了二间二晚房无烟房！酒店大堂很气派公共区域宽敞大气：还有酒店?博物馆?瀑布，?入住时前台接待说给一间安静房一间吵的（下面在施工）我说我睡眠不好要静的：，她说那要停一段时间！结果等了很晚给进房！晚上睡时一阵一阵香烟味狐臭味通过排风送入房，打电话给?前台说要叫工程人员进门看，我说巳经睡了（其实是酒店陈旧）第二天一大早?下面施工开始吵（说了要安静房）马上去前台说了情况要求换房！结果等到下午3点换到上面－层还是这种情况的房间…无语。                            房间很?紧凑洗漱台紧挨着床不到半步。                                酒店进出方便，旁边5号线！', '["https://dimg04.c-ctrip.com/images/0236312000cbeojhg8C1E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.2, 1, '2023-10-03', '花园双床房', '双床房', '家庭亲子', 306, 2, 6, 8, '["安静程度","前台服务","房间设施"]'::jsonb, '安静程度', '前台服务', '房间设施'),
('68027de5e3c98b0941765b97', '由于带着小朋友入住 双床不能拼 给换了大床酒店免费给加了一张小床 服务十分之贴心周到 美中不足的就是周边的施工就算是放假期间还是早上七点就开工 给酒店的服务增加了不少难度 但也丝毫不影响我们全家对酒店的服务打好评', '["https://dimg04.c-ctrip.com/images/0234b12000cbkwmooCA63_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000cbkvjqk2B17_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000cbl0abb5A28_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-04', '红棉双床套房', '套房', '家庭亲子', 106, 0, 6, 8, '["客房服务","安静程度","整体满意度"]'::jsonb, '客房服务', '安静程度', '整体满意度'),
('68027df0e3c98b0941765b98', '国庆中秋双节出行，不仅免费升级成了套房，还送了两盒非常精美的月饼。
客房服务可以使用微信小程序，因为带了宝宝饮用水消耗特别大，点了送水服务后很快就送来了。
酒店的几个餐厅也非常nice，瀑布餐厅非常火爆。早晚都需要排队，但酒店工作人员安排得非常合理贴心，酒店环境也非常舒适，等待的过程并不会有不适的感觉；荔湾亭的菜品则是异常精致，口味也恰到好处~所有餐厅都有宝宝椅与宝宝餐具，非常贴心', '["https://dimg04.c-ctrip.com/images/0230c12000cc08qsb907E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '红棉大床套房', '套房', '家庭亲子', 192, 0, 2, 9, '["客房服务","餐饮设施","整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度'),
('68027df0e3c98b0941765b99', '非常好。员工态度和服务细致程度都很好', '["https://dimg04.c-ctrip.com/images/0230412000d8teyka5780_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000d8tfduyABFC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000d8tfnig9A23_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-19', '花园大床房', '大床房', '独自旅行', 18, 1, 4, 4, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68027df0e3c98b0941765b9a', '酒店就在地铁口，出行方便。酒店附近该有的都有。酒店大堂和后花园都非常深得人心，服务很贴心也很到位，入住时送了月饼，水果盘，退房时送了书签。酒店的博物馆，瀑布餐厅和庭日本餐厅都非常适合打卡。觉得比较满意又续住了一晚，酒店的小姐姐送了2份早餐。下次来还会选择入住！', '["https://dimg04.c-ctrip.com/images/0232g12000cbqxm46A590_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000cbqz28x2B5B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000cbqx6cwCC0E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000cbqwwwf3268_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000cbqyiuy0CF5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000cbqz2911F67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000cbqutxaD341_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000cbqzoua2587_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000cbr2s9f8ED4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-04', '花园大床房', '大床房', '家庭亲子', 130, 0, 49, 9, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027df0e3c98b0941765b9b', '虽然是老酒店，但设施和服务都不错，庭院很美', '["https://dimg04.c-ctrip.com/images/0233612000d67r02413A2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-10', '花园大床房', '大床房', '家庭亲子', 21, 0, 5, 6, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027df0e3c98b0941765b9c', '下次还住花园酒店！特别表扬前台manceey小姐姐！', '["https://dimg04.c-ctrip.com/images/02354224x8u2itbgt9DA9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d224x8u2ipc6y327A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j224x8u2ih7naFBF7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m224x8u2in7ei8F3C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d224x8u2j5jb87A11_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c224x8u2in7ejFDC8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02371224x8u2ih7nb27E6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-19', '花园大床房', '大床房', '家庭亲子', 26, 0, 15, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027df0e3c98b0941765b9d', '办入住送了一盒月饼，办退房又送了一盒月饼，小举动让这个异乡的中秋也是仪式感满满。一开始安排的房间对着施工工地，和前台沟通后爽快的换到了另一边。唯一一点小遗憾，办理入住排队很长，金卡会员的专门通道也没有开启，只能老老实实排了将近半小时。', '["https://dimg04.c-ctrip.com/images/0237412000cb4da3oF766_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-10-02', '花园大床房', '大床房', '家庭亲子', 117, 0, 12, 8, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68027df0e3c98b0941765b9e', '习惯性好评，不过有几点要说
1 卫生间和洗澡的两个平行空间，共用一扇移门，不太能理解这个设计，并且洗完澡出来面对床没有任何遮蔽物，建议能装一块百叶帘之类的。。可见图四。。
2 凌晨楼上还在跳。。隔音一般
3 服务  酒店氛围还是不错的。。', '["https://dimg04.c-ctrip.com/images/0233i12000cark8kd74C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000carocgb4083_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000caroz2v39B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000carqgp07826_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-01', '花园双床房', '双床房', '家庭亲子', 119, 0, 12, 7, '["房间设施","安静程度","前台服务"]'::jsonb, '房间设施', '安静程度', '前台服务'),
('68027df0e3c98b0941765b9f', '对于这样五星的酒店来说我只想说没有下一次了，卫生环境差到极致，设施老旧，卫生间的浴缸根本不人性化，跨进跨出安全哪来？还有绝对没有隐私可言。隔音效果极差。我明明可以免升房型的话缺被告知房间满，但是愿意接受补差价的就可以升，这是什么服务。小孩牙刷和拖鞋需要每天打电话去要。感受太差。', '["https://dimg04.c-ctrip.com/images/0236o12000cbh8lvr2996_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000cbh5pbrF474_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000cbh6kiiEF22_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000cbhdihj8F45_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.5, 1, '2023-10-03', '花园双床房', '双床房', '家庭亲子', 139, 2, 5, 8, '["卫生状况","房间设施","安静程度"]'::jsonb, '卫生状况', '房间设施', '安静程度'),
('68027df0e3c98b0941765ba0', '房间满意，免费升级的套房豪华舒适。早餐可以在一楼吃也可以在30楼的旋转餐厅吃，周到的服务真的有宾至如归的感觉', '["https://dimg04.c-ctrip.com/images/0234h12000cpqb67r4EBC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000cpqa2zqECD9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000cpqb68gBB15_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-11', '花园大床房', '大床房', '商务出差', 54, 0, 15, 8, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027df0e3c98b0941765ba1', '2025 年的第一次出行选择了广州，也是第一次来广州，不只是因为天气温暖宜人，更是因为广州有着国内最早的五星酒店。
对比之后订了广州花园酒店，体验贝律铭设计的酒店装修风格，酒店果然如其名，花园里瀑布鲜花绿草坪，五彩斑斓的锦鲤在池中畅游，酒店大堂装饰金碧辉煌，还有花园博物馆的展品，都是别具特色。此外，酒店的服务规范温馨，前台办理入住的美女 Rebecca 周到细致，还赠送了三只粉色康乃馨，入住后服务人员也十分有礼貌， 归属国内仅有的三家白金五星级酒店之榜的确恰如其分。', '["https://dimg04.c-ctrip.com/images/0230r12000i7ww745715E_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236p12000i7wwvaj2FAB_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0237312000i7wx55k5C15_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230y12000i7wsuoaA7A6_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235912000i7wwzen60AA_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235k12000i7wvcfb2FDB_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-02-01', '红棉大床套房', '套房', '家庭亲子', 235, 0, 1, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027dfae3c98b0941765ba2', '老牌酒店   低调奢华   服务比较周到   房间卫生干净   安静   床品舒服   能睡好觉   地理位置好   大堂壁画最吸引我   入住这两天都有乐队驻唱   一定要去二楼喝早茶   味道好   不是外面那些预制菜', '["https://dimg04.c-ctrip.com/images/0234l12000cahx1xzD42E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000cahwsfc021C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-30', '花园大床房', '大床房', '家庭亲子', 111, 0, 7, 8, '["整体满意度","卫生状况","安静程度"]'::jsonb, '整体满意度', '卫生状况', '安静程度'),
('68027dfae3c98b0941765ba3', '特别舒适这次给升级房间 22层小朱服务也很好', '["https://dimg04.c-ctrip.com/images/0237412000d8eu30qA19E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000d8f7kpl7040_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-18', '花园双床房', '双床房', '家庭亲子', 22, 2, 20, 5, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027dfae3c98b0941765ba4', '超级赞的酒店！
设施：硬件很好，设施齐全。去之前看评论说室外泳池没开就没带泳衣，没想到住的两天都开放的，而且看起来很大很干净，没有体验到有点可惜。
服务：超级棒！工作人员很热情，客房服务响应及时。
环境：大堂超级大，但是有条有序。地理位置很方便，出门步行两分钟就能到达地铁站。环境更加没话说了，花园式的酒店，拥有双瀑布，使酒店显得更加豪华。
最后下飞机收到酒店的短信，提醒我有东西遗忘，联系后立马给我快递了出来，超级贴心有没有！100分！', '["https://dimg04.c-ctrip.com/images/0235v12000ccksq8r902D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000ccktzlsA3DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000cckwel6ED38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000cckthh82CD2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000cckrowz03F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000cckv5nxF45C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000cckx8uo7442_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 219, 0, 13, 9, '["公共设施","前台服务","交通便利性"]'::jsonb, '公共设施', '前台服务', '交通便利性'),
('68027dfae3c98b0941765ba5', '服务真的很好，入住送月饼，户外泳池游泳送饮料，每一层电梯厅都有服务人员，有问必答。花园很美，鱼很肥，酒店也很美，各处的设计用尽心思。瀑布早餐和30楼旋转早餐都不错，5星标准。唯一美中不足是房间的格局尤其是卫生间的隔断设计不太合理，灯光系统最好能全面分开。隔壁马路在施工，法定节假日7:30就开工，建议尽量避开21-34这些房间号。
国庆长假来说1000出头的价格也算是比较合适、出门就是地铁，周边美食也很多不错的选择。', '["https://dimg04.c-ctrip.com/images/0231z12000cbrbs8pC590_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000cbr9olu5FC0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000cbrfzpv939D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000cbrejw7F924_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-10-04', '花园双床房', '双床房', '家庭亲子', 209, 0, 11, 9, '["前台服务","整体满意度","性价比"]'::jsonb, '前台服务', '整体满意度', '性价比'),
('68027dfae3c98b0941765ba6', '酒店十分赞，这次入住刚好是中秋国庆节，办理入住就收到了中秋礼物有点小惊喜。酒店有30+年历史，里面内涵丰富，早餐丰盛，有米其林餐厅，还有博物馆，这个是最大的亮点。服务周到，下次来广州还想住这里。', '["https://dimg04.c-ctrip.com/images/0230c12000cawzn3u6C84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000caxeeolE2AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000caxdffpE381_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-01', '花园大床房', '大床房', '其他', 97, 0, 9, 8, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027dfae3c98b0941765ba7', '很久没有过来花园酒店住宿，这次回来发现房间全部都装修了，真的好太多，还是熟悉的地方，熟悉的味道，可惜有点晚没吃上荔湾亭的晚餐，下次回广州还是住花园酒店。瀑布酒吧的驻唱很不错，唱得挺好，一个人也不会觉得无聊。一直都是我最喜欢的酒店之一，还要回来……', '["https://dimg04.c-ctrip.com/images/0235b12000c9o5qfc1D9F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000c9o5qnkB2B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000c9o5tlk0D9C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-28', '花园大床房', '大床房', '商务出差', 123, 1, 17, 7, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68027dfae3c98b0941765ba8', '房间舒适，服务很好，早餐不错，宾客盈门，圣诞氛围满满。出行交通方便，步行地铁网约车出租方式任选。下次还来。', '["https://dimg04.c-ctrip.com/images/0231t12000cp0byngE8C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000cp0ds964283_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000cp0c8or3CB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000cp0dspw087A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000cp0e616B9CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000cp0d6x9D20B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-07', '花园大床房', '大床房', '家庭亲子', 53, 0, 12, 6, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027dfae3c98b0941765ba9', '酒店都很好', '["https://dimg04.c-ctrip.com/images/0235q12000dfb3w2tB180_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-16', '花园双床房', '双床房', '家庭亲子', 5, 0, 2, 1, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027dfae3c98b0941765baa', '这次和父母一起入住广州花园酒店带来不少惊喜，房间被免费升级，交通又是如此方便，楼下就有地铁，到景点都在半小时圈内，叫车也很快，一进门花香四溢，不愧网红酒店', '["https://dimg04.c-ctrip.com/images/0231l12000cl77p3d4B79_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000cl7axxi8FC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000cl7c2u2CD3C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000cl78o0v003B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-17', '花园大床房', '大床房', '家庭亲子', 77, 0, 40, 8, '["交通便利性","整体满意度","前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务'),
('68027dfae3c98b0941765bab', '办理入住的时候，还给房间升了级;房间内设施完备，重新装修后整体看着挺新的;每天都打扫得很干净;酒店内的服务人员都很热情具有较好的服务意识;离店的时候，大堂的接待李文小姐姐还送了小礼物。', '["https://dimg04.c-ctrip.com/images/0233m12000ja6det4650C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000ja5mkt5F044_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000ja6i3dgC469_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-24', '花园双床房', '双床房', '家庭亲子', 92, 0, 9, 8, '["前台服务","房间设施","卫生状况"]'::jsonb, '前台服务', '房间设施', '卫生状况'),
('68027e0be3c98b0941765bac', '升级了房间，花园式酒店，非常不错??', '["https://dimg04.c-ctrip.com/images/0230212000d89nkgd8DA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000d89of4j2013_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000d89p0m2C05B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000d89ihxd25F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000d89opc9480B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-17', '红棉大床套房', '套房', '家庭亲子', 18, 0, 12, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e0be3c98b0941765bad', '太惊喜了！
中秋节前一天入住，前台妹妹直接送了一盒月饼，还有康乃馨。
房间虽然比较老了，但很干净也很大。送的欢迎点心也是很应景的流心月饼，好好吃！客房真的是手写的欢迎函，很有心！
酒店的小花园和博物馆都很有意思。
晚餐在酒店的桃园馆订了套餐，非常惊喜，有创意，味道也是好吃的！
早餐可以在瀑布餐厅吃，但是太多人啦，于是去了旋转餐厅。煮河粉的时候真的给我了好多牛腩让我实现牛腩自由。
每个工作人员的服务意识都很强。', '["https://dimg04.c-ctrip.com/images/0230112000cdiaych5CF9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000cdias74EE04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000cdia0wn01E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000cdi5vza4AC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000cdidxit7058_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000cdi6mm1C694_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-12', '红棉大床套房', '套房', '朋友出游', 206, 0, 40, 9, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('68027e0be3c98b0941765bae', '酒店环境真的是超级赞啊！真不愧是花园酒店！白金五星酒店名副其实！', '["https://dimg04.c-ctrip.com/images/0235q12000cxn3f2u21CE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-14', '花园双床房', '双床房', '家庭亲子', 32, 0, 6, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e0be3c98b0941765baf', '酒店很不错很大，老牌酒店服务到位，Betty热情服务并升级了房间，还参观了酒店博物馆，非常精致，很好的入住体验。推荐入住！', '["https://dimg04.c-ctrip.com/images/0236h12000et71jz545FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000et7agd3DB96_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000et6wgkh835F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-17', '花园双床房', '双床房', '家庭亲子', 61, 0, 24, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027e0be3c98b0941765bb0', '非常好的酒店，各方面都很好，下次还会选择', '["https://dimg04.c-ctrip.com/images/0233a12000d67yx4n2C01_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000d67k9rzA1EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000d67iq9cA3D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000d67s7cqBD8E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-10', '红棉大床套房', '套房', '家庭亲子', 20, 0, 24, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e0be3c98b0941765bb1', '老牌五星级酒店，历史悠久，人文气息浓郁，酒店内有多个不错的餐厅，瀑布花园很赞。', '["https://dimg04.c-ctrip.com/images/0230u12000dem8c7tE994_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-03-13', '城央绿意大床房', '大床房', '朋友出游', 39, 0, 8, 6, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027e0be3c98b0941765bb2', '房间老旧，如果不是办事的地方在旁边绝对不会再住！！！洗澡居然必须得站浴缸洗，外面500的4星的酒店也不是这个条件啊。建议如非必要不要来住！', '["https://dimg04.c-ctrip.com/images/0232812000cmcu13s946C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-11-23', '花园大床房', '大床房', '商务出差', 69, 0, 2, 7, '["房间设施","性价比"]'::jsonb, '房间设施', '性价比', NULL),
('68027e0be3c98b0941765bb3', '酒店整体温馨，舒适，服务也很到位，很不错', '["https://dimg04.c-ctrip.com/images/0230112000dbbrlpbC64B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000dbbi97kFD6C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-29', '花园双床房', '双床房', '家庭亲子', 20, 0, 2, 4, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027e0be3c98b0941765bb4', '一家有历史、有故事、有美食、有美景、有服务的名副其实的“五星”酒店，不愧是羊城标志性的场所。随便提一句，交通超便利，出门百米即是地铁站。', '["https://dimg04.c-ctrip.com/images/0235812000ckai8yzA240_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000ckadzfz3B6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000ckafas8A876_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000ckab7gd1407_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000ckaaro4D693_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000ckaihcrBA05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000cka9zg58572_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000ckaf3xy3C49_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000cka9s8c1851_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-13', '红棉大床套房', '套房', '朋友出游', 68, 0, 22, 8, '["交通便利性","整体满意度","餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施'),
('68027e0be3c98b0941765bb5', '酒店各种人员都态度超好，外籍员工是最热情的，很喜欢。', '["https://dimg04.c-ctrip.com/images/0235m12000d2j7ruc99D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000d2j20obB54A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000d2j8nxhA97C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-29', '花园双床房', '双床房', '家庭亲子', 26, 0, 3, 5, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68027e16e3c98b0941765bb6', '第四次入住这家酒店，非常的不错', '["https://dimg04.c-ctrip.com/images/0236d12000d89wwaq746B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-17', '花园大床房', '大床房', '情侣出游', 15, 0, 2, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e16e3c98b0941765bb7', '酒店很棒，服务也很棒，很多外宾、很多空姐空少都入住这家酒店，看到每位工作人员都能游刃有余的与外宾们沟通办理业务，大气高水准。房间里有两个洗漱台和两台电视，真是太方便了，还配备了胶囊咖啡机，入住时按人数赠送了酒吧体验券，可惜带着娃不方便，没能体验到，酒店里的花园和博物馆深得娃的喜爱，退房时还送了小礼品，开心。早餐在一楼的瀑布餐厅或二楼荔湾亭，一楼大多是外宾，西式早餐居多，二楼有中式早餐，一楼排队人太多了，工作人员引导至二楼用餐，餐食品种不算多，将就随便填些肚子，中午去顺德再吃丰盛点吧。对了，晚餐在荔湾亭，叉烧真是太好吃了，粥也很美味，地道的粤菜很棒，酒店博物馆里有不少收获，带娃参观酒店也算是不错的行程，千万别错过。', '["https://dimg04.c-ctrip.com/images/0234p12000btyg4vw063B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000btyd65v1522_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000btygq5jE3FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000btydn8v2C8B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000btyem3e62D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000btyb44u8712_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000btygncpA41A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000bty9zsr52FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000btygrhwC9BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-05', '花园大床房', '大床房', '家庭亲子', 310, 4, 23, 9, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('68027e16e3c98b0941765bb8', '房间：这次住在1518房间，窗户朝着酒店里面，可以看到瀑布。套房得客厅开阔，功能划分布局合理。
服务：
1.感谢Mancy在入住时给予的帮助，非常专业地根据我们的行程安排，安排了续费服务，满足了我们延迟退房的需要。
2.30层行政酒廊的服务非常赞，工作人员Carrie，Mignon和Jaismine热情周到，细心体贴，以专业的态度和服务为我们的居住就下了美好的回忆。
借助携程平台表达对工作人员的赞美和感谢，既是一种习惯，也是一种不断提醒自己感恩的方式。
每一次愉快旅行的背后，都是所有工作人员的付出和努力！
Thank you for the excellent help and service you''ve provided. Your great job contributes to the  charm of this hotel.', '["https://dimg04.c-ctrip.com/images/0235n12000d4il9b8114B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-04', '粤韵双床套房', '套房', '家庭亲子', 373, 0, 22, 9, '["前台服务","整体满意度","景观/朝向"]'::jsonb, '前台服务', '整体满意度', '景观/朝向'),
('68027e16e3c98b0941765bb9', '没住过服务这么好的酒店！！！每个服务人员，都非常贴心。包括每天打扫的阿姨！请重点表扬这几天打扫2049房间的阿姨，谢谢！几乎每天都会换床品，把房间打扫得干干净净。本来只打算住两天，没想到不知不觉，陆陆续续住了一个星期。不知道为什么会有人吐槽，酒店设施差？？明明就是要什么有什么，有健身房，游泳池，甚至有发廊，博物馆，还有四五个特色餐厅。基本上不出门都能品尝到广州的各式美食。总之有各种各样舒服且完善的服务。房间内风景也很不错，各种设施虽然不算很新，但至少是齐全便利的。这可是开了几十年的酒店啊，有一些设施比较老旧也正常吧（反正我觉得不老旧）。就是一个实打实的五星级酒店啊！如果我不是没那么奢侈（有钱），我可以在花园酒店住上一年哈哈哈哈哈哈。广州这个城市，有花园酒店真是太好了。中秋节还送了贺卡和下午茶（月饼）。最后，再次感谢服务过我的所有花园工作人员！下次还会继续选择住花园酒店！我爱花园！', '["https://dimg04.c-ctrip.com/images/0206312000c9w88zhBC42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0201712000c9w9s973271_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0203112000c9w53bb5821_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0206a12000c9wix05EFEC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0206d12000c9wmza8886A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0201212000c9w7hioA694_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-28', '花园大床房', '大床房', '独自旅行', 395, 0, 4, 9, '["客房服务","整体满意度","公共设施"]'::jsonb, '客房服务', '整体满意度', '公共设施'),
('68027e16e3c98b0941765bba', '服务：非常惊喜的一次入住，名不虚传，酒店岭南风味十足，前台BETTY服务贴心，美中不足的是因为入住游客太多排队时间久，酒廊水果空了补充不及时。
设施：新装修客房很不错。房间空调温度难调，感觉清洗没有很勤。
环境：整个在花园中感觉，有设计美感。
卫生：客房、公区整体都很不错。
